import{_ as a,c as r,o as t,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Интеграция z.ai: подробности границ возможностей | Antigravity-Manager","description":"Освойте границы интеграции z.ai в Antigravity Tools. Узнайте маршрутизацию запросов, разделение потоков dispatch_mode, сопоставление моделей, стратегию безопасности заголовков, а также обратный прокси и ограничения MCP, избегайте неправильных суждений.","frontmatter":{"title":"Интеграция z.ai: подробности границ возможностей | Antigravity-Manager","sidebarTitle":"Справочник границ z.ai","subtitle":"Интеграция z.ai: подробности границ возможностей","description":"Освойте границы интеграции z.ai в Antigravity Tools. Узнайте маршрутизацию запросов, разделение потоков dispatch_mode, сопоставление моделей, стратегию безопасности заголовков, а также обратный прокси и ограничения MCP, избегайте неправильных суждений.","tags":["z.ai","MCP","Claude","Границы возможностей"],"prerequisite":["start-getting-started","platforms-mcp"],"order":3},"headers":[],"relativePath":"ru/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md","filePath":"ru/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md"}'),i={name:"ru/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md"};function d(c,e,l,s,n,p){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="границы-возможностеи-интеграции-z-ai-реализовано-vs-явно-не-реализовано" tabindex="-1">Границы возможностей интеграции z.ai (реализовано vs явно не реализовано) <a class="header-anchor" href="#границы-возможностеи-интеграции-z-ai-реализовано-vs-явно-не-реализовано" aria-label="Permalink to &quot;Границы возможностей интеграции z.ai (реализовано vs явно не реализовано)&quot;">​</a></h1><p>Этот документ рассказывает только о &quot;границах&quot; интеграции z.ai в Antigravity Tools, не о &quot;как подключить&quot;. Если вы обнаружите, что какая-то возможность не работает, сначала сравните здесь: она не включена, не настроена, или вообще не реализована.</p><h2 id="чему-вы-научитесь" tabindex="-1">Чему вы научитесь <a class="header-anchor" href="#чему-вы-научитесь" aria-label="Permalink to &quot;Чему вы научитесь&quot;">​</a></h2><ul><li>Определить, стоит ли рассчитывать на z.ai для дела: что &quot;реализовано&quot;, что &quot;документ явно не сделал&quot;</li><li>Понять, на какие точки доступа влияет z.ai (и какие точки доступа совсем не затрагиваются)</li><li>Увидеть доказательства исходного кода/документа для каждого вывода (с ссылками на строки GitHub), удобно для вашей собственной проверки</li></ul><h2 id="ваша-текущая-проблема" tabindex="-1">Ваша текущая проблема <a class="header-anchor" href="#ваша-текущая-проблема" aria-label="Permalink to &quot;Ваша текущая проблема&quot;">​</a></h2><p>Вы уже открыли z.ai в Antigravity Tools, но при использовании вы столкнулись с этими сомнениями:</p><ul><li>Почему некоторые запросы идут на z.ai, некоторые совсем не идут?</li><li>Можно ли использовать точки доступа MCP как &quot;полный MCP Server&quot;?</li><li>Переключатели, видимые в UI, действительно соответствуют реальной реализации?</li></ul><h2 id="что-такое-интеграция-z-ai-в-этом-проекте" tabindex="-1">Что такое интеграция z.ai (в этом проекте)? <a class="header-anchor" href="#что-такое-интеграция-z-ai-в-этом-проекте" aria-label="Permalink to &quot;Что такое интеграция z.ai (в этом проекте)?&quot;">​</a></h2><p><strong>Интеграция z.ai</strong> в Antigravity Tools - это необязательный &quot;апстрим провайдер + расширение MCP&quot;. Он принимает запросы протокола Claude только при определенных условиях и предоставляет обратный прокси MCP Search/Reader и минимальный встроенный сервер Vision MCP; это не решение полной замены всех протоколов и всех возможностей.</p><div class="info custom-block"><p class="custom-block-title">Одно предложение для запоминания</p><p>Вы можете рассматривать z.ai как &quot;необязательный апстрим для запросов Claude +一组 переключаемых точек доступа MCP&quot;, не считайте это &quot;полностью перенести все возможности z.ai&quot;.</p></div><h2 id="реализовано-стабильно-доступно-основано-на-исходном-коде" tabindex="-1">Реализовано: стабильно доступно (основано на исходном коде) <a class="header-anchor" href="#реализовано-стабильно-доступно-основано-на-исходном-коде" aria-label="Permalink to &quot;Реализовано: стабильно доступно (основано на исходном коде)&quot;">​</a></h2><h3 id="_1-только-протокол-claude-идет-на-z-ai-v1-messages-v1-messages-count-tokens" tabindex="-1">1) Только протокол Claude идет на z.ai (/v1/messages + /v1/messages/count_tokens) <a class="header-anchor" href="#_1-только-протокол-claude-идет-на-z-ai-v1-messages-v1-messages-count-tokens" aria-label="Permalink to &quot;1) Только протокол Claude идет на z.ai (/v1/messages + /v1/messages/count_tokens)&quot;">​</a></h3><p>Пересылка апстрима Anthropic z.ai происходит только в ветке z.ai Claude handler:</p><ul><li><code>POST /v1/messages</code>: когда <code>use_zai=true</code>, вызывает <code>forward_anthropic_json(...)</code> для пересылки JSON запроса на точку доступа Anthropic совместимости z.ai</li><li><code>POST /v1/messages/count_tokens</code>: когда z.ai включен, также пересылается; иначе возвращает placeholder <code>{input_tokens:0, output_tokens:0}</code></li></ul><p>Доказательства:</p><ul><li>выбор ветки z.ai и точка входа пересылки: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L256-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>ветка z.ai count_tokens и возвращение placeholder: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1186-L1209" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>реализация пересылки Anthropic z.ai: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L133-L219" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li></ul><div class="tip custom-block"><p class="custom-block-title">Как понимать &quot;потоковый ответ&quot;?</p><p><code>forward_anthropic_json</code> вернет тело ответа апстрима клиенту потоково через <code>bytes_stream()</code>, не разбирая SSE (см. построение тела ответа в <code>providers/zai_anthropic.rs</code>).</p></div><h3 id="_2-реальное-значение-режима-планирования-dispatch-mode" tabindex="-1">2) &quot;Реальное значение&quot; режима планирования (dispatch_mode) <a class="header-anchor" href="#_2-реальное-значение-режима-планирования-dispatch-mode" aria-label="Permalink to &quot;2) &quot;Реальное значение&quot; режима планирования (dispatch_mode)&quot;">​</a></h3><p><code>dispatch_mode</code> определяет, будет ли <code>/v1/messages</code> идти на z.ai:</p><table tabindex="0"><thead><tr><th>dispatch_mode</th><th>Что произойдет</th><th>Доказательство</th></tr></thead><tbody><tr><td><code>off</code></td><td>Никогда не использовать z.ai</td><td><code>src-tauri/src/proxy/config.rs#L20-L37</code> + <code>src-tauri/src/proxy/handlers/claude.rs#L282-L314</code></td></tr><tr><td><code>exclusive</code></td><td>Все запросы Claude идут на z.ai</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L285-L314</code></td></tr><tr><td><code>fallback</code></td><td>Пул Google недоступен (0 аккаунтов или &quot;нет доступных аккаунтов&quot;) тогда идти на z.ai</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L288-L305</code></td></tr><tr><td><code>pooled</code></td><td>Использовать z.ai как &quot;дополнительный слот&quot; в round-robin (не гарантирует попадание)</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L306-L312</code></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Распространенное недопонимание pooled</p><p><code>pooled</code> - это не &quot;и z.ai, и пул аккаунтов Google используются, и стабильное разделение по весу&quot;. В коде явно написано &quot;no strict guarantees&quot;, по сути это слот round-robin (на z.ai идет только когда <code>slot == 0</code>).</p></div><h3 id="_3-сопоставление-моделеи-как-имена-моделеи-claude-превращаются-в-glm-z-ai" tabindex="-1">3) Сопоставление моделей: как имена моделей Claude превращаются в glm-* z.ai? <a class="header-anchor" href="#_3-сопоставление-моделеи-как-имена-моделеи-claude-превращаются-в-glm-z-ai" aria-label="Permalink to &quot;3) Сопоставление моделей: как имена моделей Claude превращаются в glm-* z.ai?&quot;">​</a></h3><p>Перед пересылкой на z.ai, если в теле запроса есть поле <code>model</code>, оно будет переписано:</p><ol><li>Точное сопоставление <code>proxy.zai.model_mapping</code> (одновременно поддерживает исходную строку и lower-case key)</li><li>Префикс <code>zai:&lt;model&gt;</code>: убрать <code>zai:</code> и использовать напрямую</li><li><code>glm-*</code>: оставить без изменений</li><li>Не <code>claude-*</code>: оставить без изменений</li><li><code>claude-*</code> и содержит <code>opus/haiku</code>: сопоставить с <code>proxy.zai.models.opus/haiku</code>; иначе по умолчанию <code>sonnet</code></li></ol><p>Доказательство: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L13-L37" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L149-L152" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></p><h3 id="_4-стратегия-безопасности-заголовков-при-пересылке-избегать-утечки-локального-ключа-прокси" tabindex="-1">4) Стратегия безопасности заголовков при пересылке (избегать утечки локального ключа прокси) <a class="header-anchor" href="#_4-стратегия-безопасности-заголовков-при-пересылке-избегать-утечки-локального-ключа-прокси" aria-label="Permalink to &quot;4) Стратегия безопасности заголовков при пересылке (избегать утечки локального ключа прокси)&quot;">​</a></h3><p>Пересылка апстрима z.ai не &quot;пронесет все заголовки как есть&quot;, а сделала две линии защиты:</p><ul><li>Пропустить только небольшую часть заголовков (например, <code>content-type</code>, <code>accept</code>, <code>anthropic-version</code>, <code>user-agent</code>)</li><li>Ввести ключ API z.ai в апстрим (приоритет сохранить метод аутентификации, используемый клиентом: <code>x-api-key</code> или <code>Authorization: Bearer ...</code>)</li></ul><p>Доказательства:</p><ul><li>Белый список заголовков: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L70-L89" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li><li>Введение z.ai auth: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L91-L110" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li></ul><h2 id="реализовано-mcp-обратныи-прокси-search-reader-встроенныи-vision" tabindex="-1">Реализовано: MCP (обратный прокси Search/Reader + встроенный Vision) <a class="header-anchor" href="#реализовано-mcp-обратныи-прокси-search-reader-встроенныи-vision" aria-label="Permalink to &quot;Реализовано: MCP (обратный прокси Search/Reader + встроенный Vision)&quot;">​</a></h2><h3 id="_1-mcp-search-reader-обратныи-прокси-к-точкам-доступа-mcp-z-ai" tabindex="-1">1) MCP Search/Reader: обратный прокси к точкам доступа MCP z.ai <a class="header-anchor" href="#_1-mcp-search-reader-обратныи-прокси-к-точкам-доступа-mcp-z-ai" aria-label="Permalink to &quot;1) MCP Search/Reader: обратный прокси к точкам доступа MCP z.ai&quot;">​</a></h3><p>Локальные точки доступа и адрес апстрима жестко прописаны:</p><table tabindex="0"><thead><tr><th>Локальная точка доступа</th><th>Адрес апстрима</th><th>Переключатель</th><th>Доказательство</th></tr></thead><tbody><tr><td><code>/mcp/web_search_prime/mcp</code></td><td><code>https://api.z.ai/api/mcp/web_search_prime/mcp</code></td><td><code>proxy.zai.mcp.web_search_enabled</code></td><td><code>src-tauri/src/proxy/handlers/mcp.rs#L115-L135</code></td></tr><tr><td><code>/mcp/web_reader/mcp</code></td><td><code>https://api.z.ai/api/mcp/web_reader/mcp</code></td><td><code>proxy.zai.mcp.web_reader_enabled</code></td><td><code>src-tauri/src/proxy/handlers/mcp.rs#L137-L157</code></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">404 не &quot;сетевая проблема&quot;</p><p>Пока <code>proxy.zai.mcp.enabled=false</code>, или соответствующий <code>web_search_enabled/web_reader_enabled=false</code>, эти точки доступа напрямую вернут 404.</p></div><p>Доказательства:</p><ul><li>Общий переключатель MCP и проверка ключа z.ai: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L52-L59" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>Регистрация маршрутов: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L157-L169" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></li></ul><h3 id="_2-vision-mcp-встроенныи-сервер-минимальныи-streamable-http-mcp" tabindex="-1">2) Vision MCP: встроенный сервер &quot;минимальный Streamable HTTP MCP&quot; <a class="header-anchor" href="#_2-vision-mcp-встроенныи-сервер-минимальныи-streamable-http-mcp" aria-label="Permalink to &quot;2) Vision MCP: встроенный сервер &quot;минимальный Streamable HTTP MCP&quot;&quot;">​</a></h3><p>Vision MCP - это не обратный прокси, это локальная встроенная реализация:</p><ul><li>Точка доступа: <code>/mcp/zai-mcp-server/mcp</code></li><li><code>POST</code> поддерживает: <code>initialize</code>, <code>tools/list</code>, <code>tools/call</code></li><li><code>GET</code> возвращает SSE keepalive (требует инициализированную сессию)</li><li><code>DELETE</code> завершает сессию</li></ul><p>Доказательства:</p><ul><li>Основная точка входа handler и диспетчеризация методов: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L376-L397" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>Реализация <code>initialize</code>, <code>tools/list</code>, <code>tools/call</code>: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L229-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>Позиционирование &quot;минимальной реализации&quot; Vision MCP: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L17-L37" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></li></ul><h3 id="_3-набор-инструментов-vision-mcp-8-штук-и-ограничение-размера-фаила" tabindex="-1">3) Набор инструментов Vision MCP (8 штук) и ограничение размера файла <a class="header-anchor" href="#_3-набор-инструментов-vision-mcp-8-штук-и-ограничение-размера-фаила" aria-label="Permalink to &quot;3) Набор инструментов Vision MCP (8 штук) и ограничение размера файла&quot;">​</a></h3><p>Список инструментов из <code>tool_specs()</code>:</p><ul><li><code>ui_to_artifact</code></li><li><code>extract_text_from_screenshot</code></li><li><code>diagnose_error_screenshot</code></li><li><code>understand_technical_diagram</code></li><li><code>analyze_data_visualization</code></li><li><code>ui_diff_check</code></li><li><code>analyze_image</code></li><li><code>analyze_video</code></li></ul><p>Доказательство: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L166-L270" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L45-L53" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></p><p>Локальные файлы будут прочитаны и закодированы в <code>data:&lt;mime&gt;;base64,...</code>, при этом есть жесткое ограничение:</p><ul><li>Верхний предел изображений 5 МБ (<code>image_source_to_content(..., 5)</code>)</li><li>Верхний предел видео 8 МБ (<code>video_source_to_content(..., 8)</code>)</li></ul><p>Доказательство: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L57-L111" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a></p><h2 id="явно-не-реализовано-не-ожидаите-основано-на-заявлениях-документа-и-деталях-реализации" tabindex="-1">Явно не реализовано / Не ожидайте (основано на заявлениях документа и деталях реализации) <a class="header-anchor" href="#явно-не-реализовано-не-ожидаите-основано-на-заявлениях-документа-и-деталях-реализации" aria-label="Permalink to &quot;Явно не реализовано / Не ожидайте (основано на заявлениях документа и деталях реализации)&quot;">​</a></h2><h3 id="_1-мониторинг-использования-бюджета-z-ai-не-реализован" tabindex="-1">1) Мониторинг использования/бюджета z.ai не реализован <a class="header-anchor" href="#_1-мониторинг-использования-бюджета-z-ai-не-реализован" aria-label="Permalink to &quot;1) Мониторинг использования/бюджета z.ai не реализован&quot;">​</a></h3><p><code>docs/zai/implementation.md</code> явно написано &quot;not implemented yet&quot;. Это означает:</p><ul><li>Вы не можете рассчитывать на Antigravity Tools для предоставления запроса/бюджета z.ai или оповещений</li><li>Управление квотой (Quota Protection) также не будет автоматически считывать данные бюджета/использования z.ai</li></ul><p>Доказательство: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></p><h3 id="_2-vision-mcp-не-является-полным-mcp-server" tabindex="-1">2) Vision MCP не является полным MCP Server <a class="header-anchor" href="#_2-vision-mcp-не-является-полным-mcp-server" aria-label="Permalink to &quot;2) Vision MCP не является полным MCP Server&quot;">​</a></h3><p>Vision MCP в настоящее время позиционируется как &quot;минимальная реализация, достаточно для вызова инструментов&quot;: prompts/resources, resumability, streamed tool output и т.д. еще не сделаны.</p><p>Доказательство: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L34-L36" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></p><h3 id="_3-v1-models-claude-не-будет-отражать-реальныи-список-моделеи-z-ai" tabindex="-1">3) <code>/v1/models/claude</code> не будет отражать реальный список моделей z.ai <a class="header-anchor" href="#_3-v1-models-claude-не-будет-отражать-реальныи-список-моделеи-z-ai" aria-label="Permalink to &quot;3) `/v1/models/claude` не будет отражать реальный список моделей z.ai&quot;">​</a></h3><p>Список моделей, возвращаемый этой точкой доступа, поступает из локального встроенного сопоставления и пользовательского сопоставления (<code>get_all_dynamic_models</code>), не будет запрашивать <code>/v1/models</code> апстрима z.ai.</p><p>Доказательства:</p><ul><li>handler: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1162-L1183" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>логика генерации списка: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L84-L132" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></li></ul><h2 id="справочник-полеи-конфигурации-связано-с-z-ai" tabindex="-1">Справочник полей конфигурации (связано с z.ai) <a class="header-anchor" href="#справочник-полеи-конфигурации-связано-с-z-ai" aria-label="Permalink to &quot;Справочник полей конфигурации (связано с z.ai)&quot;">​</a></h2><p>Конфигурация z.ai находится в <code>ProxyConfig.zai</code>, включает эти поля:</p><ul><li><code>enabled</code> / <code>base_url</code> / <code>api_key</code></li><li><code>dispatch_mode</code> (<code>off/exclusive/pooled/fallback</code>)</li><li><code>model_mapping</code> (точное сопоставление покрытие)</li><li><code>models.{opus,sonnet,haiku}</code> (сопоставление по умолчанию для семейства Claude)</li><li><code>mcp.{enabled,web_search_enabled,web_reader_enabled,vision_enabled}</code></li></ul><p>Значения по умолчанию (base_url / модели по умолчанию) также в том же файле:</p><ul><li><code>base_url = &quot;https://api.z.ai/api/anthropic&quot;</code></li><li><code>opus/sonnet = &quot;glm-4.7&quot;</code></li><li><code>haiku = &quot;glm-4.5-air&quot;</code></li></ul><p>Доказательство: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L20-L116" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L265-L279" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></p><hr><h2 id="краткии-итог-урока" tabindex="-1">Краткий итог урока <a class="header-anchor" href="#краткии-итог-урока" aria-label="Permalink to &quot;Краткий итог урока&quot;">​</a></h2><ul><li>z.ai в настоящее время будет принимать только протокол Claude (<code>/v1/messages</code> + <code>count_tokens</code>), другие точки доступа протокола не &quot;автоматически идут на z.ai&quot;</li><li>MCP Search/Reader - это обратный прокси; Vision MCP - это локальная минимальная реализация, не полный MCP Server</li><li>Список моделей <code>/v1/models/claude</code> поступает из локального сопоставления, не представляет реальные модели апстрима z.ai</li></ul><hr><h2 id="следующии-урок预告" tabindex="-1">Следующий урок预告 <a class="header-anchor" href="#следующии-урок预告" aria-label="Permalink to &quot;Следующий урок预告&quot;">​</a></h2><blockquote><p>Следующий урок мы изучим <strong><a href="/docs/opencodedocs/ru/lbjlaq/Antigravity-Manager/changelog/release-notes/">Версионная эволюция</a></strong>.</p></blockquote><hr><h2 id="приложение-справка-по-исходному-коду" tabindex="-1">Приложение: Справка по исходному коду <a class="header-anchor" href="#приложение-справка-по-исходному-коду" aria-label="Permalink to &quot;Приложение: Справка по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы увидеть местоположение исходного кода</strong></summary><blockquote><p>Обновлено: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>Область интеграции z.ai (протокол Claude + MCP + Vision MCP)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L12-L17" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></td><td>12-17</td></tr><tr><td>Режим планирования z.ai и значения по умолчанию моделей</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L20-L116" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>20-116</td></tr><tr><td>z.ai base_url по умолчанию / модели по умолчанию</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L265-L279" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>265-279</td></tr><tr><td>Логика выбора, идет ли <code>/v1/messages</code> на z.ai</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L256-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>256-374</td></tr><tr><td>Пересылка z.ai <code>/v1/messages/count_tokens</code> и возвращение placeholder</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1186-L1209" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>1186-1209</td></tr><tr><td>Пересылка апстрима Anthropic z.ai (пересылка JSON + потоковый возврат ответа)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L133-L219" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>133-219</td></tr><tr><td>Правила сопоставления моделей z.ai (map_model_for_zai)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L13-L37" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>13-37</td></tr><tr><td>Белый список заголовков + введение z.ai auth</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L70-L110" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>70-110</td></tr><tr><td>Обратный прокси MCP Search/Reader и переключатели</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L45-L157" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></td><td>45-157</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Позиционирование минимальной реализации Vision MCP (не полный MCP Server)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L17-L37" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></td><td>17-37</td></tr><tr><td>Список инструментов Vision и ограничения (tool_specs + размер файла + stream=false)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L57-L270" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a></td><td>57-270</td></tr><tr><td>Источник списка моделей <code>/v1/models/claude</code> (локальное сопоставление, не запрос к апстриму)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L84-L132" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></td><td>84-132</td></tr><tr><td>Мониторинг использования/бюджета не реализован (заявление документа)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></td><td>194-198</td></tr></tbody></table></details>',76)])])}const b=a(i,[["render",d]]);export{u as __pageData,b as default};
